declare @allocationMethod char(1)
select @allocationMethod = rtrim(val) from options where name = 'm_pp_pb'
select 'this._voucherCode='@@id';this._allocationMethod=' + @allocationMethod + ';load$GridVoucherDetail$(this);' as message
return





        select 'dispose$GridVoucherDetail$(this);' as message
return






      /* <flatten type="Javascript"> */
function load$GridVoucherDetail$(g) {
  g.add_itemValueChanged(onChange$GridVoucherDetail$);
  g.add_commandEvent(on$GridVoucherDetail$ExecuteCommand);
  g.$a = {
    gia: '[gia]:=[gia_nt]*[$ty_gia]',
    nguyen_gia: '[nguyen_gia]:=[nguyen_gia_nt]*[$ty_gia]',
    nguyen_gia_sl: '[nguyen_gia]:=[so_luong]*[gia]',
    nguyen_gia_sl_nt: '[nguyen_gia_nt]:=[so_luong]*[gia_nt]',
    gt_da_pb : '[gt_da_pb]:=[gt_da_pb_nt]*[$ty_gia]',
    gt_pb_ky: '[gt_pb_ky]:=[gt_pb_ky_nt]*[$ty_gia]',
    gt_pb_ky_ng: '[gt_pb_ky]:=[$so_ky_pb]==0 ? 0 : [nguyen_gia]/[$so_ky_pb]',
    gt_pb_ky_cl: '[gt_pb_ky]:=[$so_ky_pb]==0 ? 0 : [gt_cl]/[$so_ky_pb]',
    gt_cl: '[gt_cl]:=[gt_cl_nt]*[$ty_gia]',

    gt_cl_nt: '[gt_cl_nt]:=[nguyen_gia_nt] - [gt_da_pb_nt]',
    gt_cl_tl: '[gt_cl]:=[nguyen_gia] - [gt_da_pb]',
    gt_pb_ky_nt_ng: '[gt_pb_ky_nt]:=[$so_ky_pb] ==0 ? 0 : [nguyen_gia_nt]/[$so_ky_pb]',
    gt_pb_ky_nt_cl: '[gt_pb_ky_nt]:=[$so_ky_pb] ==0 ? 0 : [gt_cl_nt]/[$so_ky_pb]',

    t_nguyen_gia_nt: ['t_nguyen_gia_nt', 'nguyen_gia_nt'],
    t_gt_da_pb_nt: ['t_gt_da_pb_nt', 'gt_da_pb_nt'],
    t_gt_cl_nt: ['t_gt_cl_nt', 'gt_cl_nt'],
    t_gt_pb_ky_nt: ['t_gt_pb_ky_nt', 'gt_pb_ky_nt'],

    t_nguyen_gia: ['t_nguyen_gia', 'nguyen_gia'],
    t_gt_da_pb: ['t_gt_da_pb', 'gt_da_pb'],
    t_gt_cl: ['t_gt_cl', 'gt_cl'],
    t_gt_pb_ky: ['t_gt_pb_ky', 'gt_pb_ky']
  };
}
function dispose$GridVoucherDetail$(g) {
  g.$a = null;
  try {g.remove_commandEvent(on$GridVoucherDetail$ExecuteCommand);} catch (ex) {}
  try {g.remove_itemValueChanged(onChange$GridVoucherDetail$);} catch (ex) {}
}
function onChange$GridVoucherDetail$(sender, eventArgs) {
  var o = eventArgs.get_object(), g = o.grid, f = g.get_element().parentForm, name = o.field.Name;
  switch (name) {
    case 'so_luong':
      g.validExpression(o, [g.$a.nguyen_gia_sl_nt, g.$a.nguyen_gia, g.$a.gt_cl_nt, g.$a.gt_pb_ky_nt_ng, g.$a.gt_pb_ky, g.$a.gt_cl], [g.$a.t_nguyen_gia_nt, g.$a.t_gt_cl_nt, g.$a.t_gt_pb_ky_nt, g.$a.t_nguyen_gia, g.$a.t_gt_cl, g.$a.t_gt_pb_ky]);
      break;
    case 'gia_nt':
      g.validExpression(o, [g.$a.gia, g.$a.nguyen_gia_sl_nt, g.$a.nguyen_gia, g.$a.gt_cl_nt, g.$a.gt_pb_ky_nt_ng, g.$a.gt_pb_ky, g.$a.gt_cl], [g.$a.t_nguyen_gia_nt, g.$a.t_gt_cl_nt, g.$a.t_gt_pb_ky_nt, g.$a.t_nguyen_gia, g.$a.t_gt_cl, g.$a.t_gt_pb_ky]);
      break;
    case 'nguyen_gia_nt':
      g.validExpression(o, [g.$a.nguyen_gia, g.$a.gt_cl_nt, g.$a.gt_pb_ky_nt_ng, g.$a.gt_pb_ky, g.$a.gt_cl], [g.$a.t_nguyen_gia_nt, g.$a.t_gt_cl_nt, g.$a.t_gt_pb_ky_nt, g.$a.t_nguyen_gia, g.$a.t_gt_cl, g.$a.t_gt_pb_ky]);
      break;
    case 'gt_da_pb_nt':
      if (g._allocationMethod == 1) g.validExpression(o, [g.$a.gt_da_pb, g.$a.gt_pb_ky_ng, g.$a.gt_cl_nt, g.$a.gt_cl, g.$a.gt_pb_ky_nt_ng], [g.$a.t_gt_da_pb_nt, g.$a.t_gt_cl_nt, g.$a.t_gt_pb_ky_nt, g.$a.t_gt_da_pb, g.$a.t_gt_cl, g.$a.t_gt_pb_ky]);
        else g.validExpression(o, [g.$a.gt_da_pb, g.$a.gt_pb_ky, g.$a.gt_cl_nt, g.$a.gt_cl, g.$a.gt_pb_ky_nt_cl], [g.$a.t_gt_da_pb_nt, g.$a.t_gt_cl_nt, g.$a.t_gt_pb_ky_nt, g.$a.t_gt_da_pb, g.$a.t_gt_cl, g.$a.t_gt_pb_ky]);
      break;
    case 'gt_cl_nt':
      g.validExpression(o, [g.$a.gt_cl], [g.$a.t_gt_cl_nt, g.$a.t_gt_cl]);
      break;
    case 'gt_pb_ky_nt':
      g.validExpression(o, [g.$a.gt_pb_ky], [g.$a.t_gt_pb_ky_nt, g.$a.t_gt_pb_ky]);
      break;
    case 'gia':
      if (g._allocationMethod == 1) g.validExpression(o, [g.$a.nguyen_gia_sl, g.$a.gt_pb_ky_ng, g.$a.gt_cl_tl], [g.$a.t_nguyen_gia, g.$a.t_gt_cl, g.$a.t_gt_pb_ky]);
        else g.validExpression(o, [g.$a.nguyen_gia_sl, g.$a.gt_cl_tl, g.$a.gt_pb_ky_cl], [g.$a.t_nguyen_gia, g.$a.t_gt_cl, g.$a.t_gt_pb_ky]);
      break;
    case 'nguyen_gia':
      if (g._allocationMethod == 1) g.validExpression(o, [g.$a.gt_pb_ky_ng, g.$a.gt_cl_tl], [g.$a.t_nguyen_gia, g.$a.t_gt_cl, g.$a.t_gt_pb_ky]);
        else g.validExpression(o, [g.$a.gt_cl_tl, g.$a.gt_pb_ky_cl], [g.$a.t_nguyen_gia, g.$a.t_gt_cl, g.$a.t_gt_pb_ky]);
      break;
    case 'gt_da_pb':
      if (g._allocationMethod == 1) g.validExpression(o, [g.$a.gt_cl_tl, g.$a.gt_pb_ky_ng], [g.$a.t_gt_da_pb, g.$a.t_gt_cl, g.$a.t_gt_pb_ky]);
        else g.validExpression(o, [g.$a.gt_cl_tl, g.$a.gt_pb_ky_cl], [g.$a.t_gt_da_pb, g.$a.t_gt_cl, g.$a.t_gt_pb_ky]);
      break;
    case 'gt_pb_ky':
      g.validExpression(o, [g.$a.gt_pb_ky], [g.$a.t_gt_pb_ky]);
      break;
    default:
      break;
  }
}
function on$GridVoucherDetail$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender, f = g.get_element().parentForm;
  switch (action) {
    case 'AfterRemoveRow':
      on$GridVoucherDetail$RowChange(g, f);
      break;
    case 'AfterCloneRow':
      g.setItemFieldValue('stt_rec0', e.type.Value, '');
      on$GridVoucherDetail$RowChange(g, f);
      break;
    default:
      break;
  }
}
function on$GridVoucherDetail$RowChange(g, f) {g.executeAggregate([g.$a.t_nguyen_gia_nt, g.$a.t_gt_da_pb_nt, g.$a.t_gt_cl_nt, g.$a.t_gt_pb_ky_nt, g.$a.t_nguyen_gia, g.$a.t_gt_da_pb, g.$a.t_gt_cl, g.$a.t_gt_pb_ky]);}
